use tokio::sync::mpsc;

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::channel::<String>(32);  // buffer size 32

    // Spawn a producer
    let tx2 = tx.clone();  // Clone for multiple producers
    tokio::spawn(async move {
        tx.send("hello from task 1".into()).await.unwrap();
    });
    tokio::spawn(async move {
        tx2.send("hello from task 2".into()).await.unwrap();
    });

    // Receive messages
    while let Some(msg) = rx.recv().await {
        println!("Received: {}", msg);
    }
}

use tokio::sync::oneshot;

async fn compute(input: u32, reply: oneshot::Sender<u64>) {
    let result = (input as u64) * (input as u64);
    let _ = reply.send(result);  // Send response back
}

#[tokio::main]
async fn main() {
    let (tx, rx) = oneshot::channel();

    tokio::spawn(compute(42, tx));

    let result = rx.await.unwrap();
    println!("42 squared = {}", result);
}

use tokio::sync::broadcast;

#[tokio::main]
async fn main() {
    let (tx, _) = broadcast::channel::<String>(16);

    let mut rx1 = tx.subscribe();
    let mut rx2 = tx.subscribe();

    tokio::spawn(async move {
        while let Ok(msg) = rx1.recv().await {
            println!("Subscriber 1: {}", msg);
        }
    });
    tokio::spawn(async move {
        while let Ok(msg) = rx2.recv().await {
            println!("Subscriber 2: {}", msg);
        }
    });

    tx.send("event A".into()).unwrap();
    tx.send("event B".into()).unwrap();

    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
}

use tokio::sync::watch;

#[tokio::main]
async fn main() {
    let (tx, mut rx) = watch::channel("initial config".to_string());

    tokio::spawn(async move {
        loop {
            rx.changed().await.unwrap();
            println!("Config updated to: {}", *rx.borrow());
        }
    });

    tx.send("updated config v1".to_string()).unwrap();
    tx.send("updated config v2".to_string()).unwrap();

    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
}
